WITH trip_blocks AS ( SELECT t.trip_id, t.title AS trip_title, item, CASE WHEN COALESCE(item ->> 'content_id', item ->> 'contentId') ~ '^[0-9]+$' THEN COALESCE(item ->> 'content_id', item ->> 'contentId')::integer ELSE NULL END AS content_id FROM trips t CROSS JOIN LATERAL jsonb_array_elements( CASE WHEN jsonb_typeof(t.data -> 'items') = 'array' THEN t.data -> 'items' ELSE '[]'::jsonb END ) item WHERE t.group_id = #{groupId} AND t.end_date < CURRENT_DATE ), block_media AS ( SELECT tb.trip_id, tb.trip_title, tb.item, tb.content_id, media FROM trip_blocks tb CROSS JOIN LATERAL jsonb_array_elements( CASE WHEN jsonb_typeof(tb.item -> 'media') = 'array' THEN tb.item -> 'media' ELSE '[]'::jsonb END ) media ) SELECT bm.trip_id, bm.trip_title, NULLIF(bm.item ->> 'visitDate', '')::date AS visit_date, bm.item ->> 'id' AS block_id, bm.item ->> 'title' AS block_title, bm.content_id, a.title AS attraction_title, a.sido_code, s.sido_name, a.gugun_code, g.gugun_name, COALESCE( CASE WHEN bm.item ->> 'lat' ~ '^-?[0-9]+(\.[0-9]+)?$' THEN (bm.item ->> 'lat')::double precision END, a.latitude ) AS latitude, COALESCE( CASE WHEN bm.item ->> 'lng' ~ '^-?[0-9]+(\.[0-9]+)?$' THEN (bm.item ->> 'lng')::double precision END, a.longitude ) AS longitude, bm.media ->> 'type' AS media_type, bm.media ->> 'url' AS media_url, COALESCE(bm.media -> 'metadata', '{}'::jsonb) AS metadata FROM block_media bm LEFT JOIN attractions a ON a.content_id = bm.content_id LEFT JOIN sidos s ON s.sido_code = a.sido_code LEFT JOIN guguns g ON g.sido_code = a.sido_code AND g.gugun_code = a.gugun_code WHERE bm.media ->> 'url' IS NOT NULL AND bm.media ->> 'url' <> ''
AND a.sido_code = #{request.sidoCode}
AND a.gugun_code = #{request.gugunCode}
AND bm.content_id = #{request.contentId}
AND UPPER(bm.media ->> 'type') = #{request.mediaType}
ORDER BY bm.trip_id DESC, visit_date ASC NULLS LAST, block_id ASC, media_url ASC

